 var lowLoad = numPrompts <= 2000 && requestRate <= 8

+// truncateString returns the first n characters of s, appending "..." if truncated.
+func truncateString(s string, n int) string {
+	if len(s) <= n {
+		return s
+	}
+	return s[:n] + "..."
+}
+
